from sklearn.datasets import fetch_20newsgroups, make_multilabel_classification
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.naive_bayes import MultinomialNB
from sklearn.linear_model import LogisticRegression
import requests
import json

def train():
    emails = fetch_20newsgroups(categories=['rec.sport.baseball', 'sci.crypt'], 
    shuffle=True, random_state=42).data

    voc = CountVectorizer().fit(emails)
    train_set = voc.transform(emails)

    X = train_set; y = [0 if m=='rec.sport.baseball' else 1 for m in emails]
    model = LogisticRegression()
    model.fit(X,y)

    return voc, model

def test():
    testcases = [['This game is cool', 0], ['You are wrong', 1]]
    return json.loads(requests.post('http://localhost:9527/test/', 
        data=json.dumps({'cases': [testcases]})).text)['results']

def main():
    print('voc: {}'.format([t[0] for t in voc.vocabulary_.items()][0]))

if __name__ == '__main__':
    voc, model = train();
    main();